module top_module(
    input clk,
    input rst,
    input [3:0] bin_in,
    output [3:0] dec_out,
    output valid_out
);reg [3:0] unused_dec_out_reg;
reg valid_out_reg;

always @(posedge clk) begin
    if (rst) begin
        unused_dec_out_reg <= 0;
        valid_out_reg <= 0;
    end
    else begin
        case (bin_in)
            4'b0000: unused_dec_out_reg <= 4'b0000;
            4'b0001: unused_dec_out_reg <= 4'b0001;
            4'b0010: unused_dec_out_reg <= 4'b0010;
            4'b0011: unused_dec_out_reg <= 4'b0011;
            4'b0100: unused_dec_out_reg <= 4'b0100;
            4'b0101: unused_dec_out_reg <= 4'b0101;
            4'b0110: unused_dec_out_reg <= 4'b0110;
            4'b0111: unused_dec_out_reg <= 4'b0111;
            4'b1000: unused_dec_out_reg <= 4'b1000;
            4'b1001: unused_dec_out_reg <= 4'b1001;
            4'b1010: unused_dec_out_reg <= 4'b1010;
            4'b1011: unused_dec_out_reg <= 4'b1011;
            4'b1100: unused_dec_out_reg <= 4'b1100;
            4'b1101: unused_dec_out_reg <= 4'b1101;
            4'b1110: unused_dec_out_reg <= 4'b1110;
            4'b1111: unused_dec_out_reg <= 4'b1111;
        endcase
        valid_out_reg <= 1;
    end
end

assign dec_out = unused_dec_out_reg;
assign valid_out = valid_out_reg;

endmodule
